/*@ Import Coq Require Import count_positive */

int count_positive(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == count_positive_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int cnt = 0;

    /*@ Inv
          0 <= i && i <= n &&
          a == a@pre &&
          n == n@pre &&
          cnt == count_positive_spec(sublist(0, i, l)) &&
          IntArray::full(a, n, l)
    */
    for (i = 0; i < n; ++i) {
        if (a[i] > 0) {
            cnt++;
        }
    }

    /*@ Assert
          i == n &&
          a == a@pre &&
          n == n@pre &&
          cnt == count_positive_spec(l) &&
          IntArray::full(a, n, l)
    */
    return cnt;
}

